def lcs_length(a, b):
    # a, b strings
    n, m = len(a), len(b)
    # DP row optimization
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        ai = a[i-1]
        for j in range(1, m+1):
            temp = dp[j]
            if ai == b[j-1]:
                dp[j] = prev + 1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = temp
    return dp[m]

