def tokens(s):
    s_norm = normalize_ar(s)
    return s_norm.split()

def token_precision(span, text):
    a = tokens(span)
    b = tokens(text)
    if not a or not b:
        return 0.0
    inter = sum(1 for t in a if t in b)
    return inter / len(a)

def token_f1(span, text):
    a = tokens(span); b = tokens(text)
    if not a or not b:
        return 0.0
    set_a = set(a); set_b = set(b)
    inter = len(set_a & set_b)
    prec = inter / len(set_a)
    rec = inter / len(set_b)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

