def lcs_length2(a, b):
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(n):
        new = [0]*(m+1)
        for j in range(m):
            if a[i] == b[j]:
                new[j+1] = dp[j] + 1
            else:
                new[j+1] = dp[j+1] if dp[j+1] >= new[j] else new[j]
        dp = new
    return dp[m]

def sim_norm_lcs2(a, b):
